  showtime8: [
    { taskNumber: 1, title: "Part 1", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "Sometimes we underestimate the power of ordinary words. We think they're just sound - phrases that vanish the moment they're spoken. But words remain. They can lift someone in their hardest hour - or wound in ways remembered for years.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 2, title: "Part 2", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "A single 'you can do it' can give a person courage to try. And a single 'you won't make it' can stop them in their tracks. Words shape how we see ourselves and how we see others. And the most important thing is - we choose which words to speak.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 3, title: "Part 3", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "We can use them to tear down, or to build up. To support. To inspire. To give hope. One word spoken at the right moment can change someone's day - or even their whole life. So before you speak, ask yourself: will your word leave a mark, and what kind?", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
  ],
