  showtime10: [
    { taskNumber: 1, title: "Part 1", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "Fear is a feeling we want to run from. To hide. To delay. To tell ourselves, 'Later.' But ask yourself - why are we afraid of these specific moments? Why is it scary to speak? To try? To take a step?", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 2, title: "Part 2", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "Because it matters. We don't fear what we don't care about. We fear what could change us. What carries risk. What carries chance. What carries growth. Fear isn't a 'stop' sign - it's a 'something important is here' sign.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 3, title: "Part 3", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "Every time you stand before a choice to step forward or stay put, fear will be there too. And it is exactly in that moment that you decide who you'll become. Courage is not the absence of fear. It is the decision to go forward despite it. And one day you may look back and realize - everything you feared was a door you finally opened.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
  ],
  reading10: [
    { taskNumber: 1, title: "Ernest Hemingway: The Old Man and the Sea (1)", instruction: "Read the prose naturally, bring out the imagery, hold pauses between sentences.", content: "He was an old man who fished alone in a skiff in the Gulf Stream and he had gone eighty-four days now without taking a fish. In the first forty days a boy had been with him.", tips: ["Don't rush", "Each sentence is a picture", "Natural pauses"] },
    { taskNumber: 2, title: "Ernest Hemingway: The Old Man and the Sea (2)", instruction: "Read the prose naturally, bring out the imagery, hold pauses between sentences.", content: "But after forty days without a fish the boy's parents had told him that the old man was now definitely and finally salao, which is the worst form of unlucky, and the boy had gone at their orders in another boat which caught three good fish the first week.", tips: ["Don't rush", "Each sentence is a picture", "Natural pauses"] },
    { taskNumber: 3, title: "Ernest Hemingway: The Old Man and the Sea (3)", instruction: "Read the prose naturally, bring out the imagery, hold pauses between sentences.", content: "It made the boy sad to see the old man come in each day with his skiff empty and he always went down to help him carry either the coiled lines or the gaff and harpoon and the sail that was furled around the mast.", tips: ["Don't rush", "Each sentence is a picture", "Natural pauses"] },
  ],
