  tonguetwister12: [
    { taskNumber: 1, title: "Tongue twister 1", instruction: "Say it three times: slow, medium, fast. Don't lose clarity.", content: "Eleven benevolent elephants.", tips: ["Start slowly", "Clarity matters more than speed", "Active articulation"] },
    { taskNumber: 2, title: "Tongue twister 2", instruction: "Say it three times: slow, medium, fast. Don't lose clarity.", content: "Lesser leather never weathered wetter weather better.", tips: ["Start slowly", "Clarity matters more than speed", "Active articulation"] },
    { taskNumber: 3, title: "Tongue twister 3", instruction: "Say it three times: slow, medium, fast. Don't lose clarity.", content: "A skunk sat on a stump. The stump thunk the skunk stunk.", tips: ["Start slowly", "Clarity matters more than speed", "Active articulation"] },
  ],
  showtime12: [
    { taskNumber: 1, title: "Part 1", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "Sometimes the world seems too large for one person to change anything in it. We look at global problems and think our voice is just a drop. But every large world is made of small stories and individual people. Every change that ever happened began with one person.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 2, title: "Part 2", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "Someone who didn't wait for another to take the first step. Who decided to say a word, make a choice, reach out a hand, try - despite the fear. And in that moment they probably didn't think they were changing the world - they were just doing what felt right. But choices like that start a chain.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 3, title: "Part 3", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "One act influences another person, who influences the next - and gradually it becomes something larger. The world doesn't change all at once or loudly. It changes quietly, through those who don't walk past. The real question isn't whether you can change the whole world - but whether you're ready to change a small part of it.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
  ],
  reading12: [
    { taskNumber: 1, title: "Aesop: The Lion and the Mouse (1)", instruction: "Read the fable as a living scene: change voices, play characters, highlight the moral.", content: "A Lion lay asleep in the forest, his great head resting on his paws. A timid little Mouse came upon him unexpectedly, and in her fright and haste to get away, ran across the Lion's nose.", tips: ["Narrator stays calm", "Characters get distinct voices", "Deliver the moral with weight"] },
    { taskNumber: 2, title: "Aesop: The Lion and the Mouse (2)", instruction: "Read the fable as a living scene: change voices, play characters, highlight the moral.", content: "Roused from his nap, the Lion laid his huge paw angrily on the tiny creature to kill her. 'Spare me!' begged the poor Mouse. 'Please let me go and some day I will surely repay you.' The Lion was much amused and let her go.", tips: ["Narrator stays calm", "Characters get distinct voices", "Deliver the moral with weight"] },
    { taskNumber: 3, title: "Aesop: The Lion and the Mouse (3)", instruction: "Read the fable as a living scene: change voices, play characters, highlight the moral.", content: "Some days later, while stalking his prey in the forest, the Lion was caught in the toils of a hunter's net. The Mouse heard his angry roar and ran to help. She gnawed the ropes until the Lion was free. A kindness is never wasted.", tips: ["Narrator stays calm", "Characters get distinct voices", "Deliver the moral with weight"] },
  ],
