  showtime19: [
    { taskNumber: 1, title: "Part 1", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "Questions aren't just a way to get information. They are a tool of thought that lets us go beyond the obvious. To doubt, to search, to understand more deeply, to see more than what's on the surface. Because of questions, a person grows.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 2, title: "Part 2", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "Every question is an admission that you don't know everything. Which means you have room for growth, for new ideas, for discoveries. People who stop asking questions begin to take everything for granted. They stop analyzing, stop searching for meaning - and their growth slows.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 3, title: "Part 3", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "But those who keep asking 'why,' 'how,' and 'what for' stay in motion. Strength isn't in having every answer. It's in not being afraid to ask the right questions.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
  ],
