  showtime20: [
    { taskNumber: 1, title: "Part 1", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "A person is rarely shaped alone. Our views, habits, behavior, even our thoughts are formed by those we spend time with. By the conversations we hear. By the atmosphere we live in every day. An environment can quietly push us toward growth, inspire us, lift us in hard moments.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 2, title: "Part 2", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "Or it can limit us, make us doubt ourselves, and stop us from moving forward. The hardest part is that this influence isn't always obvious. It happens gradually - through small things, ordinary words, repeated situations.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 3, title: "Part 3", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "Because in the long run, your environment becomes part of you. Choose the people around you as carefully as you choose your path. Because they are part of that path too.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
  ],
