  showtime21: [
    { taskNumber: 1, title: "Part 1", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "Unlike money, opportunities, or even energy - time is the only resource you cannot get back. It cannot be saved or replenished. Every minute lived without attention is gone forever. We often postpone decisions, conversations, dreams, and actions for later.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 2, title: "Part 2", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "Without realizing that 'later' is not a guaranteed point - just an assumption. At some moment we understand: missed opportunities cannot be reclaimed. Unspoken words remain unspoken. Unmade steps remain unmade. But there is strength in this too.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 3, title: "Part 3", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "Knowing the value of time makes us see life differently. We choose more consciously. Act more boldly. Stop postponing what truly matters. The best way to respect your time is to use it here and now.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
  ],
  reading21: [
    { taskNumber: 1, title: "Aesop: The Ant and the Grasshopper (1)", instruction: "Read the fable as a living scene: change voices, play characters, highlight the moral.", content: "In a field one summer's day a Grasshopper was hopping about, chirping and singing to its heart's content. An Ant passed by, bearing along with great toil an ear of corn he was taking to the nest.", tips: ["Narrator stays calm", "Characters get distinct voices", "Deliver the moral with weight"] },
    { taskNumber: 2, title: "Aesop: The Ant and the Grasshopper (2)", instruction: "Read the fable as a living scene: change voices, play characters, highlight the moral.", content: "'Why not come and chat with me,' said the Grasshopper, 'instead of toiling and moiling in that way?' 'I am helping to lay up food for the winter,' said the Ant, 'and recommend you to do the same.'", tips: ["Narrator stays calm", "Characters get distinct voices", "Deliver the moral with weight"] },
    { taskNumber: 3, title: "Aesop: The Ant and the Grasshopper (3)", instruction: "Read the fable as a living scene: change voices, play characters, highlight the moral.", content: "'Why bother about winter?' said the Grasshopper; 'we have got plenty of food at present.' But the Ant went on its way and continued its toil. When the winter came the Grasshopper had no food and found itself dying of hunger.", tips: ["Narrator stays calm", "Characters get distinct voices", "Deliver the moral with weight"] },
  ],
