  showtime22: [
    { taskNumber: 1, title: "Part 1", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "In a world that keeps accelerating, it's easy to think only speed has value. That what matters is arriving first - faster than others, faster than yesterday. But in that race we often lose the most important thing - movement itself. Speed only matters when you're already heading in the right direction.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 2, title: "Part 2", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "If you stand still, even perfect conditions lead nowhere. Sometimes a person takes slow steps, doubts, pauses, and continues again. From outside this can look like hesitation. But growth, experience, and understanding all happen inside that very process.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 3, title: "Part 3", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "A fast start without awareness can lead to burnout. So what matters isn't how fast you go, but that you don't stop. Movement, even slow, always leads further than perfect speed without action.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
  ],
  reading22: [
    { taskNumber: 1, title: "Ernest Hemingway: The Old Man and the Sea (1)", instruction: "Read the prose naturally, bring out the imagery, hold pauses between sentences.", content: "He was an old man who fished alone in a skiff in the Gulf Stream and he had gone eighty-four days now without taking a fish. In the first forty days a boy had been with him.", tips: ["Don't rush", "Each sentence is a picture", "Natural pauses"] },
    { taskNumber: 2, title: "Ernest Hemingway: The Old Man and the Sea (2)", instruction: "Read the prose naturally, bring out the imagery, hold pauses between sentences.", content: "But after forty days without a fish the boy's parents had told him that the old man was now definitely and finally salao, which is the worst form of unlucky, and the boy had gone at their orders in another boat which caught three good fish the first week.", tips: ["Don't rush", "Each sentence is a picture", "Natural pauses"] },
    { taskNumber: 3, title: "Ernest Hemingway: The Old Man and the Sea (3)", instruction: "Read the prose naturally, bring out the imagery, hold pauses between sentences.", content: "It made the boy sad to see the old man come in each day with his skiff empty and he always went down to help him carry either the coiled lines or the gaff and harpoon and the sail that was furled around the mast.", tips: ["Don't rush", "Each sentence is a picture", "Natural pauses"] },
  ],
