  showtime23: [
    { taskNumber: 1, title: "Part 1", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "In a world where people rush, compete, and try not to show weakness, kindness can seem like something simple - or even naive. But it is one of the strongest forms of influence a person can have. Kindness needs no special conditions and depends on no status.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 2, title: "Part 2", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "It shows in words, in tone, in the ability to notice another person and not pass them by. Sometimes one kind word can change someone's day. Support them when it's most needed. Remind them they're not alone. Kindness changes not only those it's directed at.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 3, title: "Part 3", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "It changes the one who offers it. Makes them stronger, calmer, more sure of themselves. In a world where so much can be hard - staying kind is already strength.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
  ],
  reading23: [
    { taskNumber: 1, title: "Kipling: If (1)", instruction: "Read the poem with measured rhythm, intonation, and pauses.", content: "If you can keep your head when all about you\nAre losing theirs and blaming it on you,\nIf you can trust yourself when all men doubt you,\nBut make allowance for their doubting too.", tips: ["Feel the meter", "Each image is a picture", "End with breath"] },
    { taskNumber: 2, title: "Kipling: If (2)", instruction: "Read the poem with measured rhythm, intonation, and pauses.", content: "If you can wait and not be tired by waiting,\nOr being lied about, don't deal in lies,\nOr being hated, don't give way to hating,\nAnd yet don't look too good, nor talk too wise.", tips: ["Feel the meter", "Each image is a picture", "End with breath"] },
    { taskNumber: 3, title: "Kipling: If (3)", instruction: "Read the poem with measured rhythm, intonation, and pauses.", content: "Yours is the Earth and everything that's in it,\nAnd - which is more - you'll be a Man, my son!\nIf you can fill the unforgiving minute\nWith sixty seconds' worth of distance run.", tips: ["Feel the meter", "Each image is a picture", "End with breath"] },
  ],
