  showtime25: [
    { taskNumber: 1, title: "Part 1", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "Art is often seen as something extra - something optional. Something that exists for inspiration or entertainment. But its role is much deeper. Through art, a person learns to feel, to understand, and to express what plain words cannot carry.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 2, title: "Part 2", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "Music, painting, literature, theater - all of it reflects human experience. It makes emotions and lives accessible to others. Even when those others live in different times and conditions. Art connects people. It creates a space where we can pause, reflect, and see ourselves from the outside.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 3, title: "Part 3", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "It helps us understand not only the world, but ourselves. The real value of art is its ability to call forth a response. Where there is art, there is life, emotion, and depth.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
  ],
