  showtime26: [
    { taskNumber: 1, title: "Part 1", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "Life often presents moments when it seems easier to take a shortcut. To gain quickly, bend rules, or stretch the truth to get a result. In the moment, it may look like a reasonable choice. But such choices almost always carry consequences.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 2, title: "Part 2", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "Short-term gain rarely brings long-term peace. Honesty isn't just a principle. It is the foundation of trust. And trust cannot be bought or quickly rebuilt once lost. When a person stays honest - even when it's harder -", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 3, title: "Part 3", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "they keep what matters most: self-respect and the trust of those around them. Over time, this becomes the real value. Profit can vanish, but reputation and inner rightness remain.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
  ],
