  showtime28: [
    { taskNumber: 1, title: "Part 1", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "When we think of communication, we picture words, arguments, eloquence. We assume that's what shapes how we're perceived. But there are things that work more quietly, more simply - and yet more deeply. One of them is a smile.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 2, title: "Part 2", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "A smile needs no preparation and no explanation. It can change the atmosphere of a room in a moment. It softens conversation, releases tension, creates openness and trust. It shows that in front of you isn't just words - but a person ready to connect.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 3, title: "Part 3", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "That's its strength: it works without effort, yet leaves warmth behind. Sometimes a smile is the very moment real conversation begins. And most importantly - when we smile, we become a little more open to the world ourselves. Smile more often.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
  ],
