  showtime31: [
    { taskNumber: 1, title: "Part 1", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "When we hear the word 'respect,' we often see it as something external. As rules of behavior, politeness, the right words. We assume that if we don't rude or interrupt, that's enough. But respect isn't only about behavior.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 2, title: "Part 2", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "It's about attitude. About the ability to see another person as a whole person. With their own experience, views, and feelings. Respect shows in how we listen, how we respond, how we accept what differs from us. To respect doesn't mean to agree.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 3, title: "Part 3", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "It means to acknowledge another person's right to be different. In a world full of arguments, it is respect that lets us understand instead of destroy. Respect begins with a simple thought: in front of you is a person whose life matters as much as yours.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
  ],
