  showtime32: [
    { taskNumber: 1, title: "Part 1", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "When we think about confident speech, it seems to be only about voice or polished phrasing. But confidence in words isn't just form. It's a reflection of an inner state. How a person speaks directly shapes how they're perceived.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 2, title: "Part 2", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "Even the strongest thought can go unnoticed if spoken without confidence. And the opposite - simple words said with confidence sound persuasive and meaningful. Confidence isn't perfection. Not the absence of nerves. Not flawlessness. Not pretending to be better than you are.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 3, title: "Part 3", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "It's honesty about what you say. Knowing your thought. Being ready to express it, even when fear is present. The ability to speak in spite of fear is what makes speech alive and real.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
  ],
