  showtime34: [
    { taskNumber: 1, title: "Part 1", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "We often think serious change requires long years and many aligned circumstances. But if you look closer, it all starts with one decision. With one moment when a person chooses - step forward, or stay still. That decision can be small, almost unnoticeable from outside.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 2, title: "Part 2", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "Saying 'yes' where before there was 'no.' Trying where before there was fear. Beginning where before there was waiting. In the moment it doesn't seem important. But decisions like this start a chain.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 3, title: "Part 3", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "They change direction. Open new possibilities. Lead to new people and new ideas. Over time it becomes clear that everything began with that single choice. So pay attention to the decisions you make each day.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
  ],
