  showtime37: [
    { taskNumber: 1, title: "Part 1", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "When we face an important moment, anxiety becomes almost inevitable. Sometimes it feels so strong that it seems to take us over completely. It blocks our thinking, speaking, acting the way we want to. We may believe confident people are free of fear and doubt.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 2, title: "Part 2", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "But anxiety isn't a sign of weakness - it's a natural response to what matters to us. The problem isn't anxiety itself, but how we relate to it. When we treat it as an obstacle, we amplify its power over us. But if we see it differently - as energy, as readiness for action -", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 3, title: "Part 3", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "it stops being an enemy. Anxiety means you care. That you are present. The task isn't to remove it, but to learn to act together with it.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
  ],
