  showtime41: [
    { taskNumber: 1, title: "Part 1", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "When we face failure, our first reaction is often disappointment. A sense that something went wrong, that effort was wasted. In those moments it's easy to see only the negative - the mistake, the proof of our doubts. But it is in these situations that we gain experience success can never give.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 2, title: "Part 2", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "Success often gives a result. Failure gives understanding. It shows where the weak spots were, where preparation was lacking, where things should have been done differently. But most importantly - it tests how a person relates to themselves. Will they give up - or try again?", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 3, title: "Part 3", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "In that moment, failure stops being the end and becomes part of the path. It doesn't define the person. What defines them is what they do after it. Perhaps because of failure, we become the kind of people who can meet much greater challenges.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
  ],
