  showtime42: [
    { taskNumber: 1, title: "Part 1", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "The need for recognition is one of the deepest human needs. Every person needs to feel seen, heard, valued. That their effort matters and is not unnoticed. From childhood we seek confirmation - that we are doing right, that we matter, that we are needed.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 2, title: "Part 2", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "As we grow older, this need doesn't disappear - it just changes form. We want our achievements to be noticed, our words to carry weight. But here lies a subtle danger. When recognition becomes the only source of self-worth, we begin to depend on others' opinions.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 3, title: "Part 3", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "We adapt, doubt, and lose our inner compass. Any lack of approval feels like failure. It's important not to give up the wish to be recognized - but to learn to find balance. External recognition is pleasant - but the inner sense of worth is far more stable.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
  ],
