  showtime48: [
    { taskNumber: 1, title: "Part 1", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "Dear friends, let's be honest. These days, to 'stay current' you have to keep up with so many trends that sometimes it's easier to log off and live peacefully. Yesterday everyone discussed one thing. Today another. Tomorrow you'll find you missed something again. In this flow, a strange feeling appears - as if you're always slightly not where you should be.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 2, title: "Part 2", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "A bit out of the loop. A bit behind. But if you stop and ask - who actually decides what matters and what doesn't? Why do some things suddenly become 'must-knows,' while others vanish just as fast? At some point it's important to choose: chase every trend, or decide for yourself what matters.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 3, title: "Part 3", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "Staying current is pleasant. But being yourself is far more important. Thank you. See you soon.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
  ],
