  showtime49: [
    { taskNumber: 1, title: "Part 1", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "Glad to see everyone here today. Today I'll speak about something important. It must be said - we live in an amazing time. In five minutes you can see how dozens, hundreds, thousands of people live. It seems to give us choice, possibility, inspiration.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 2, title: "Part 2", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "But there is a catch. The more we watch others' lives, the more we treat them as a benchmark. Not as example, but as standard we must match. At some point you catch yourself thinking, 'Am I even living right?'", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 3, title: "Part 3", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "Even though an hour ago you were content. It isn't tragedy - it's the effect of scale. When you see too many other stories, your own starts to feel less bright. But each person has their own rhythm and priorities. Comparing them directly is like comparing different routes on the same map.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
  ],
