  showtime50: [
    { taskNumber: 1, title: "Part 1", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "If you open any video or article about productivity right now, you get the feeling that the perfect day should look like a carefully planned project. Early rise. Sport. Planning. Goals. Results. It all seems logical. But here's a question: where in all this is life itself?", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 2, title: "Part 2", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "Sometimes a day can be completely ordinary. Without records, without checked boxes, without the feeling of being maximally effective. And that doesn't make it a bad day. We're used to judging ourselves by results - but we forget that state matters too.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 3, title: "Part 3", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "You can't always be at the maximum. It just doesn't work in the long run. Sometimes the best day is the one you simply lived well with what you had. And that is already enough.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
  ],
