  showtime52: [
    { taskNumber: 1, title: "Part 1", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "By the way, there's a lot of talk now about personal boundaries. About how important it is to build them, defend them, hold them. Of course, that sounds right. But sometimes it feels like boundaries are turning into walls.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 2, title: "Part 2", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "As if every inconvenience is a reason to step away. Every disagreement, a signal to shut down. Every conflict, a reason to end communication. But boundaries aren't about closing off from everyone.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 3, title: "Part 3", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "They are about knowing where you end and another person begins. The real difficulty isn't saying 'no.' It's staying in the dialogue, even when it isn't comfortable. And here is where composure, firmness, confidence, and strength are found.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
  ],
