  showtime53: [
    { taskNumber: 1, title: "Part 1", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "At some moment in life, everyone faces a question of choice. It usually sounds not like 'what do I want,' but 'what would be right.' The right university. The right job. The right circle. The right decisions. As if there were some scheme that guarantees a calm and successful future.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 2, title: "Part 2", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "But no one has ever truly seen that scheme. For each person it somehow looks different. And the choice becomes not a search for your own path - but an attempt to guess which option will look most convincing to others.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 3, title: "Part 3", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "Perhaps at some point you should ask an unusual question. If you remove the word 'right' - what is even left? Beyond the expectations, that's often where something of your own truly begins.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
  ],
  reading53: [
    { taskNumber: 1, title: "Kipling: If (1)", instruction: "Read the poem with measured rhythm, intonation, and pauses.", content: "If you can keep your head when all about you\nAre losing theirs and blaming it on you,\nIf you can trust yourself when all men doubt you,\nBut make allowance for their doubting too.", tips: ["Feel the meter", "Each image is a picture", "End with breath"] },
    { taskNumber: 2, title: "Kipling: If (2)", instruction: "Read the poem with measured rhythm, intonation, and pauses.", content: "If you can wait and not be tired by waiting,\nOr being lied about, don't deal in lies,\nOr being hated, don't give way to hating,\nAnd yet don't look too good, nor talk too wise.", tips: ["Feel the meter", "Each image is a picture", "End with breath"] },
    { taskNumber: 3, title: "Kipling: If (3)", instruction: "Read the poem with measured rhythm, intonation, and pauses.", content: "Yours is the Earth and everything that's in it,\nAnd - which is more - you'll be a Man, my son!\nIf you can fill the unforgiving minute\nWith sixty seconds' worth of distance run.", tips: ["Feel the meter", "Each image is a picture", "End with breath"] },
  ],
