  showtime58: [
    { taskNumber: 1, title: "Part 1", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "We live in a world where everything is instant. Information, delivery, answers to questions. And we've become used to expecting everything just as fast. But the most important things in life don't come instantly.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 2, title: "Part 2", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "Trust is built over years. Mastery comes through thousands of repetitions. Deep relationships require time. And patience. Patience isn't passivity. It's the active ability to continue, even when the result isn't yet visible.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 3, title: "Part 3", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "It's faith in the process - not only the moment. Those who know how to wait receive more than those who rush. Because time is the ally of those who respect it.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
  ],
