  showtime59: [
    { taskNumber: 1, title: "Part 1", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "Gratitude is one of the most underrated feelings. We assume it should be expressed only for great gifts and great events. But real gratitude is about small things. For having your health. For having a roof over your head.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 2, title: "Part 2", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "For the person beside you. For the day you've just lived. When you start noticing reasons for gratitude, the world changes. Not because it became different, but because your perception changed. A grateful person lives richer, even with less.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 3, title: "Part 3", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "An ungrateful one lives poorer, even with everything. Say thank you out loud. Don't wait for a special reason. Because gratitude is the shortest distance between you and happiness.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
  ],
  reading59: [
    { taskNumber: 1, title: "Keats: Ode on a Grecian Urn (1)", instruction: "Read the poem with measured rhythm, intonation, and pauses.", content: "Thou still unravish'd bride of quietness,\nThou foster-child of silence and slow time,\nSylvan historian, who canst thus express\nA flowery tale more sweetly than our rhyme.", tips: ["Feel the meter", "Each image is a picture", "End with breath"] },
    { taskNumber: 2, title: "Keats: Ode on a Grecian Urn (2)", instruction: "Read the poem with measured rhythm, intonation, and pauses.", content: "Heard melodies are sweet, but those unheard\nAre sweeter; therefore, ye soft pipes, play on;\nNot to the sensual ear, but, more endear'd,\nPipe to the spirit ditties of no tone.", tips: ["Feel the meter", "Each image is a picture", "End with breath"] },
    { taskNumber: 3, title: "Keats: Ode on a Grecian Urn (3)", instruction: "Read the poem with measured rhythm, intonation, and pauses.", content: "When old age shall this generation waste,\nThou shalt remain, in midst of other woe\nThan ours, a friend to man, to whom thou say'st,\n'Beauty is truth, truth beauty.'", tips: ["Feel the meter", "Each image is a picture", "End with breath"] },
  ],
