  showtime60: [
    { taskNumber: 1, title: "Part 1", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "Forgiveness is often confused with weakness. It seems that to forgive is to agree with what happened. But it's something different. Forgiveness isn't justification of an act.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 2, title: "Part 2", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "It's the decision to stop carrying it inside. When we hold a grudge, we keep living in the past. And the past takes the energy we need for the present. Forgiveness isn't a gift to the other person. It's a gift to yourself.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 3, title: "Part 3", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "It's release from a weight that was never yours to carry. Forgiving is hard. It requires strength. And that is exactly why forgiveness belongs to strong people.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
  ],
  reading60: [
    { taskNumber: 1, title: "Aesop: The Boy Who Cried Wolf (1)", instruction: "Read the fable as a living scene: change voices, play characters, highlight the moral.", content: "A Shepherd Boy tended his master's sheep near a dark forest. It was lonely for him watching the flock, so he devised a plan to amuse himself. He ran down toward the village calling out 'Wolf, Wolf!'", tips: ["Narrator stays calm", "Characters get distinct voices", "Deliver the moral with weight"] },
    { taskNumber: 2, title: "Aesop: The Boy Who Cried Wolf (2)", instruction: "Read the fable as a living scene: change voices, play characters, highlight the moral.", content: "The villagers came running with pitchforks to drive the Wolf away. But when they arrived at the top of the hill, they found the boy doubled up with laughter at the trick he had played on them. A few days later he tried the same trick again.", tips: ["Narrator stays calm", "Characters get distinct voices", "Deliver the moral with weight"] },
    { taskNumber: 3, title: "Aesop: The Boy Who Cried Wolf (3)", instruction: "Read the fable as a living scene: change voices, play characters, highlight the moral.", content: "Then one day a Wolf really did come out from the forest. The Boy cried out 'Wolf, Wolf!' even louder than before. But the villagers thought he was trying to fool them again, and so they didn't come. Liars are not believed even when they speak the truth.", tips: ["Narrator stays calm", "Characters get distinct voices", "Deliver the moral with weight"] },
  ],
