  showtime61: [
    { taskNumber: 1, title: "Part 1", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "The hardest thing in life is being honest with yourself. With others we often play roles. With ourselves it's harder. Because you can't fool yourself for long. You can pretend everything is fine while inside is empty.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 2, title: "Part 2", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "You can convince yourself the choice is right while your heart knows otherwise. But truth always knocks. Through tiredness. Through disappointment. Through anxiety. Honesty with yourself is the beginning of any change. Without it, growth is impossible - because you can't see where to go.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 3, title: "Part 3", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "Admit your fears. Admit your desires. Admit your mistakes. This isn't weakness. It's the first step toward real strength. Because only those who know themselves can truly become themselves.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
  ],
