  showtime62: [
    { taskNumber: 1, title: "Part 1", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "We've grown used to fearing solitude. Filling silence with sound, the feed with endless scrolling, the mind with others' opinions. Anything to avoid being alone with ourselves. But it's in silence that the most important thoughts are born.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 2, title: "Part 2", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "It's in solitude that a person discovers who they really are. Without masks. Without roles. Without others' expectations. Solitude isn't a punishment. It's a space to meet yourself. Those who can be alone are not lonely.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
    { taskNumber: 3, title: "Part 3", instruction: "You're on stage. Read the excerpt expressively, feeling the audience.", content: "They are full. They are self-sufficient. And those people bring the most to others. Because you can't share what you don't have inside.", tips: ["Look forward, not at the text", "Pause after phrases", "Emphasize key words"] },
  ],
